    public static readonly IReadOnlyList<CommunicationQuizQuestion> Questions =
    [
        Q(1, "Điều gì thường được xem là \"kẻ thù\" lớn nhất cản trở việc quản lý thời gian hiệu quả?", "What is often considered the biggest enemy of effective time management?", ["Thiếu ngủ", "Sự trì hoãn", "Lịch học hoặc làm việc quá dày", "Các hoạt động ngoại khóa"], ["Lack of sleep", "Procrastination", "An overloaded study or work schedule", "Extracurricular activities"], 1, 2),
        Q(2, "Một lý do tâm lý phổ biến khiến người ta trì hoãn nhiệm vụ khó là gì?", "What is a common psychological reason people delay difficult tasks?", ["Quên hạn nộp", "Thấy nhiệm vụ quá dễ", "Sợ thất bại hoặc làm không đủ tốt", "Muốn thử thách bản thân vào phút chót"], ["Forgetting the deadline", "Finding the task too easy", "Fear of failure or not doing well enough", "Wanting a last-minute challenge"], 2, 0),
        Q(3, "Việc trì hoãn kéo dài có thể dẫn đến điều gì?", "What can prolonged procrastination lead to?", ["Tăng tính sáng tạo", "Rèn khả năng chịu áp lực", "Bỏ lỡ mục tiêu, căng thẳng và lo âu", "Giúp nhận ra việc không quan trọng"], ["More creativity", "Better pressure tolerance", "Missed goals, stress, and anxiety", "Recognizing unimportant work"], 2, 3),
