        Q(11, "Cách thông minh để tránh quá tải với một dự án lớn là gì?", "What is a smart way to avoid overload on a large project?", ["Thức trắng đêm", "Chia nhỏ dự án và phân bổ trong tuần", "Đợi sát hạn để có cảm hứng", "Làm kết luận trước"], ["Work all night", "Break it into smaller tasks distributed across the week", "Wait for deadline pressure", "Write the conclusion first"], 1, 3),
        Q(12, "Cách hiệu quả nhất để hạn chế xao nhãng từ điện thoại khi học là gì?", "What is the most effective way to limit phone distraction while studying?", ["Bật tivi làm tiếng nền", "Úp điện thoại trước mặt", "Cất điện thoại ngoài tầm mắt hoặc sang phòng khác", "Vừa học vừa trả lời nhanh"], ["Turn on the television", "Keep the phone face down nearby", "Put the phone out of sight or in another room", "Reply quickly while studying"], 2, 1),
