        Q(16, "Một cách tốt để tận dụng lại quỹ thời gian bận rộn là gì?", "What is a good way to reclaim time in a busy schedule?", ["Bỏ ăn và ngủ", "Dùng khoảng thời gian chết để làm việc nhỏ hoặc ôn nhanh", "Xin nghỉ vài buổi", "Làm hai việc phức tạp cùng lúc"], ["Skip meals and sleep", "Use waiting time for a small task or quick review", "Take several days off", "Do two complex tasks simultaneously"], 1, 2),
        Q(17, "Vì sao học nhồi nhét cả đêm trước kỳ thi gây hậu quả xấu?", "Why is all-night cramming harmful?", ["Phải uống cà phê", "Gây căng thẳng, thiếu ngủ, quá tải và giảm ghi nhớ dài hạn", "Học kiến thức ngoài đề", "Giảng viên không hài lòng"], ["It requires coffee", "It causes stress, sleep loss, overload, and poor long-term retention", "It covers material outside the test", "It displeases the lecturer"], 1, 0),
        Q(18, "Nên làm gì khi phải học một khối lượng kiến thức lớn?", "What should you do when learning a large amount of material?", ["Học liên tục bốn giờ", "Đổi hoạt động, nghỉ ngắn hoặc tự hỏi sau mỗi 10–25 phút", "Nghe nhạc thật to", "Chỉ đọc phần tóm tắt"], ["Study four hours continuously", "Switch activity, pause briefly, or self-question every 10–25 minutes", "Play loud music", "Read only the summary"], 1, 3),
        Q(19, "Vì sao nên đưa ăn, ngủ và tập thể dục vào thời gian biểu?", "Why include meals, sleep, and exercise in a schedule?", ["Để lịch trông bận rộn", "Sức khỏe thể chất và tinh thần tốt giúp làm việc hiệu quả, bền vững", "Để thể hiện kỷ luật", "Để người khác thấy chăm chỉ"], ["To make the schedule look busy", "Physical and mental health support effective, sustainable work", "To display discipline", "To impress others"], 1, 2),
        Q(20, "Hiệu ứng Domino trong quản lý thời gian có nghĩa là gì?", "What does the Domino effect mean in time management?", ["Một trì hoãn nhỏ hoặc ước lượng sai có thể ảnh hưởng hàng loạt việc sau", "Xong một việc thì mọi việc khác tự xong", "Xếp sách như quân domino", "Giải trí trước khi học"], ["A small delay or bad estimate can disrupt many later tasks", "Completing one task completes all others", "Arrange books like dominoes", "Relax before studying"], 0, 1)
